rm -f ~/.claude/cache/deepseek-balance
# 直接测试 python 解析
RESPONSE='{"is_available":true,"balance_infos":[{"currency":"CNY","total_balance":"2.20","granted_balance":"0.00","topped_up_balance":"2.20"}]}'
echo "$RESPONSE" | python3 -c "
import json,sys
try:
    data = json.load(sys.stdin)
    infos = data.get('balance_infos', [])
    for b in infos:
        if b.get('currency') == 'CNY':
            print(b.get('total_balance', '0'))
            sys.exit(0)
    if infos:
        print(infos[0].get('total_balance', '0'))
    else:
        print('0')
except:
    print('err')
" 2>&1
echo "Exit: $?"
